class Solution:
    def countDistinct(self, nums, k, p):
        """
        :type nums: List[int]
        :type k: int
        :type p: int
        :rtype: int
        """
        seen = set()
        n = len(nums)

        for i in range(n):
            divisible_count = 0
            for j in range(i, n):
                # Count elements divisible by p
                if nums[j] % p == 0:
                    divisible_count += 1

                # If too many divisible elements, stop
                if divisible_count > k:
                    break

                # Add subarray as tuple
                subarray = tuple(nums[i:j+1])
                seen.add(subarray)

        return len(seen)
